INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 100, 10142, 10.85, "2030/12/17 14:59:59", 0.0, 0.0, 100, 24, 129901, 1, "エリコ", 7, "訓練成功、おめでとうございます\n褒めるべき時にはしっかり褒めるのも\n教官の務めですものね。それとも、\n罵られる方が好みですか？　クスクス");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 101, 10142, 11.15, "2030/12/17 14:59:59", 0.0, 0.0, 101, 24, 129901, 1, "エリコ", 2, "厳しい訓練も、終わってみれば\n短く感じるものですわね。\n正直、私は暴れ足りないくらい…\nいえ、何でもありませんわ。クスクス");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 102, 10142, 6.4, "2030/12/17 14:59:59", 0.0, 0.0, 102, 24, 129901, 7, "エリコ", 5, "行く手を阻む忌々しい邪魔者を\n蹴散らして、見事ゴールイン…！\nまるで私とあのおかたの人生を\n象徴するような道のりでした…");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 103, 10142, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 103, 24, 129901, 3, "エリコ", 3, "まったくもって不甲斐ない結果です\nしかし、挽回の機会はまだありますわ\n次はゴミ虫の地位から脱却できるよう\n死力を尽くしなさい。いいですね？");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 104, 10142, 2.43, "2030/12/17 14:59:59", 0.0, 0.0, 104, 24, 129901, 2, "エリコ", 8, "クスクス…ああご心配なさらず\nなんとも情けない成績を残す輩には\nどんな罰が相応しいか、考えている\nだけですので…クスクスクス");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 105, 10142, 9.08, "2030/12/17 14:59:59", 0.0, 0.0, 105, 24, 129901, 4, "エリコ", 3, "私が教官として認められなければ、\nあのおかたを失望させてしまう…\nそれだけはあってはなりません\nあなた方も、わかっていますわね？");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 106, 10142, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 106, 24, 129901, 6, "エリコ", 6, "まずまずの結果ではありますが、\nこの程度で満足してもらっては\n困りますわ。エリコ班の一員として、\nより高みを目指していただきますので");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 107, 10142, 10.6, "2030/12/17 14:59:59", 0.0, 0.0, 107, 24, 129901, 3, "エリコ", 8, "私の指導を受けながら、この結果は…\nもっと真剣に考えねばなりませんね\nあなた方が怠けずにいるには、\nどんなしつけが必要かを…クスクス");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 108, 10142, 7.54, "2030/12/17 14:59:59", 0.0, 0.0, 108, 24, 129901, 6, "エリコ", 4, "ひとまず訓練をこなしたご褒美か、\n実力を出しきれたとは言えない罰か…\nみなさんにどちらを与えるべきか\n少し悩む結果ですわね");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 109, 10142, 11.5, "2030/12/17 14:59:59", 0.0, 0.0, 109, 24, 129901, 2, "エリコ", 7, "なかなかいい戦いぶりでしたわ\nこれもあなた方の頑張りと、何より\n優秀な教官である私の教育の賜物\nそうですわね？　クスクスクス…");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 110, 10142, 8.83, "2030/12/17 14:59:59", 0.0, 0.0, 110, 24, 129901, 2, "エリコ", 1, "これだけ進めたのならば合格点ですわ\nでも、もっと高みを目指したいと\n思っているのなら…さらなる訓練にも\n付き合って差し上げましょう");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 111, 10142, 6.68, "2030/12/17 14:59:59", 0.0, 0.0, 111, 24, 129901, 1, "エリコ", 2, "未熟で頼りなかったあなた方が、\n見違えるように成長しました\nなるほど…これこそが、教官冥利に\n尽きるという気持ちなのですね");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 112, 10142, 8.8, "2030/12/17 14:59:59", 0.0, 0.0, 112, 24, 129901, 6, "エリコ", 2, "まさかあなた方が、私の予想すら\n超える力を発揮するとは…驚きました\nもはやゴミ虫などではありません\n一人前の騎士として胸を張りなさい");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 113, 10142, 8.9, "2030/12/17 14:59:59", 0.0, 0.0, 113, 24, 129901, 2, "エリコ", 1, "クスクス、見事な働きです\nみなさんならできると信じていました\n他でもない私の指導を受けた、\nエリコ班の優秀な新兵なのですから");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 114, 10142, 3.7, "2030/12/17 14:59:59", 0.0, 0.0, 114, 24, 129901, 2, "エリコ", 5, "なんてすばらしい成績…！\n今日という日は『あのおかたを想い\nエリコが限界を超えた記念日』として\n歴史に刻まれることでしょう…！");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 200, 10142, 7.6, "2030/12/17 14:59:59", 0.0, 0.0, 200, 24, 129801, 1, "マコト", 2, "よし、いい訓練になったな\nおまえたちもよく動けてたし、\nちゃんと成長できてると思うぜ\nその調子で頑張れよっ");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 201, 10142, 2.25, "2030/12/17 14:59:59", 0.0, 0.0, 201, 24, 129801, 2, "マコト", 1, "ひとまずゴールおめでとう！\nでも、努力は継続してこそだからな\nおまえたちにやる気があるなら、\n何度だって付き合ってやるよ");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 202, 10142, 3.28, "2030/12/17 14:59:59", 0.0, 0.0, 202, 24, 129801, 2, "マコト", 1, "行軍訓練はこれにて完了！\n…なーんて思ってないよな？\n学んだことが体に染みつくまで\n地道に繰り返すのが練習ってもんさ");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 203, 10142, 2.98, "2030/12/17 14:59:59", 0.0, 0.0, 203, 24, 129801, 4, "マコト", 1, "みんなに無理をさせちまったか…\nでもこれで諦めることはないぜ\n次はきっとうまくいく。そう信じて\n鍛え続ければ、道は開けるはずだ！");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 204, 10142, 3.0, "2030/12/17 14:59:59", 0.0, 0.0, 204, 24, 129801, 4, "マコト", 1, "こいつは悔しい結果だな…\nま、反省点はいろいろあったし\nひとつずつ乗り越えていこう\nあたしたちで力を合わせて、なっ！");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 205, 10142, 10.3, "2030/12/17 14:59:59", 0.0, 0.0, 205, 24, 129801, 1, "マコト", 2, "おまえたちはまだ未熟な訓練兵、\n失敗を必要以上に悔やむことはねえよ\nでも実戦じゃこうはいかないからな\n次は気合を入れ直していけよっ！");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 206, 10142, 2.93, "2030/12/17 14:59:59", 0.0, 0.0, 206, 24, 129801, 6, "マコト", 1, "これがおまえたちの全力？\nいやいや、そんなはずはないよなっ\nおまえらならもっと強くなれる！\nあたしが言うんだ、間違いないぜ！");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 207, 10142, 9.3, "2030/12/17 14:59:59", 0.0, 0.0, 207, 24, 129801, 3, "マコト", 1, "おまえたちの実力を考えりゃ、\nベストを尽くせたとは言えない成績だ\nなら、次やるべきことも決まってる\n気持ちを切り替えて、鍛え直すんだ！");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 208, 10142, 6.9, "2030/12/17 14:59:59", 0.0, 0.0, 208, 24, 129801, 4, "マコト", 1, "まだまだ課題がある内容だったな～\n無駄な動き、判断の遅れ…\nそういうのをしっかり直していけば、\n記録ももっと伸びるはずだっ");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 209, 10142, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 209, 24, 129801, 2, "マコト", 2, "ここまでいけりゃ、合格点！\nむしろ、最初の頼りなさを思えば\nすげえ成長してるんじゃねえか？\n胸を張れる結果だと思うぜっ！");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 210, 10142, 5.95, "2030/12/17 14:59:59", 0.0, 0.0, 210, 24, 129801, 1, "マコト", 2, "なかなかハードな訓練だったけど、\nみんなしっかりついてこられたな\n地道に続けた基礎トレの成果が\n形になってる、その証だぜっ");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 211, 10142, 6.73, "2030/12/17 14:59:59", 0.0, 0.0, 211, 24, 129801, 2, "マコト", 1, "今回の訓練もよく頑張ったな！\nしっかり休んで次に備えろよ！\nなんつーか、教え子が成長してくのを\n見るのは楽しいもんだな…");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 212, 10142, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 212, 24, 129801, 2, "マコト", 2, "おまえら、すげえじゃねえか！\nこれならもう、ひよっこ新兵なんて\n言えねえな。きっと騎士団でも\n大活躍間違いなしだぜ！");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 213, 10142, 6.65, "2030/12/17 14:59:59", 0.0, 0.0, 213, 24, 129801, 1, "マコト", 2, "敵との戦い方、状況判断の正確さ\n何より根性…どれも最高だったぞ！\nうかうかしてたら、教官のあたしまで\n追い抜かれちまうかもな…へへっ");
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("2024/03/31 12:00:00", 214, 10142, 3.05, "2030/12/17 14:59:59", 0.0, 0.0, 214, 24, 129801, 6, "マコト", 1, "あたしの指導が良かった？\nいやいや、ここまで強くなれたのは、\n他でもないおまえたち自身が努力した\nおかげだよ。改めて…おめでとうっ！");
